option.raw:
const data = ctx.data?.objects || [];
return {
  title: { text: '订单漏斗', left: 'center', textStyle: { fontSize: 14 } },
  tooltip: { trigger: 'item', formatter: '{b}: {c}' },
  series: [{
    type: 'funnel', left: '10%', width: '80%', sort: 'none',
    label: { formatter: p => `${p.name.substring(2)}\n${p.value}`, fontSize: 12 },
    data: data.map(d => ({ name: d.stage, value: parseInt(d.count || 0) })),
    itemStyle: { borderWidth: 0 },
    color: ['#1677ff', '#52c41a', '#fa8c16', '#722ed1']
  }]
};
